export class StandardValidation implements ContextItem {
  message: any;

  constructor(
    private readonly validator: StandardValidator,
    private readonly negated: boolean,
    private readonly options: any[] = [],
    // For testing only.
    // Deliberately not calling it `toString` in order to not override `Object.prototype.toString`.
    private readonly stringify = toStringImpl,
  ) {}

  async run(context: Context, value: any, meta: Meta) {
    const values = Array.isArray(value) ? value : [value];
    values.forEach(value => {
      const result = this.validator(this.stringify(value), ...this.options);
      if (this.negated ? result : !result) {
        context.addError({ type: 'field', message: this.message, value, meta });
      }
    });
  }
}

return function redirect (res) {
  if (this.hasTrailingSlash()) {
    this.error(404)
    return
  }

  // get original URL
  var originalUrl = parseUrl.original(this.req)

  // append trailing slash
  originalUrl.path = null
  originalUrl.pathname = collapseLeadingSlashes(originalUrl.pathname + '/')

  // reformat the URL
  var loc = encodeUrl(url.format(originalUrl))
  var doc = createHtmlDocument('Redirecting', 'Redirecting to ' + escapeHtml(loc))

  // send redirect response
  res.statusCode = 301
  res.setHeader('Content-Type', 'text/html; charset=UTF-8')
  res.setHeader('Content-Length', Buffer.byteLength(doc))
  res.setHeader('Content-Security-Policy', "default-src 'none'")
  res.setHeader('X-Content-Type-Options', 'nosniff')
  res.setHeader('Location', loc)
  res.end(doc)
}

export interface MySqlConnectionOptions
  extends Omit<
    MySql2.ConnectionOptions,
    // The user cannot modify these options:
    // This option is currently a global Sequelize option
    | 'timezone'
    // Conflicts with our own features
    | 'nestTables'
    // We provide our own placeholders.
    // TODO: should we use named placeholders for mysql?
    | 'namedPlaceholders'
    // We provide our own pool
    | 'pool'
    // Our code expects specific response formats, setting any of the following option would break Sequelize
    | 'typeCast'
    | 'bigNumberStrings'
    | 'supportBigNumbers'
    | 'dateStrings'
    | 'decimalNumbers'
    | 'rowsAsArray'
    | 'stringifyObjects'
    | 'queryFormat'
    | 'Promise'
    // We provide our own "url" implementation
    | 'uri'
  > {}

export class PostgresQueryInterfaceTypescript<
  Dialect extends PostgresDialect = PostgresDialect,
> extends AbstractQueryInterface<Dialect> {
  readonly #internalQueryInterface: AbstractQueryInterfaceInternal;

  constructor(dialect: Dialect, internalQueryInterface?: AbstractQueryInterfaceInternal) {
    internalQueryInterface ??= new AbstractQueryInterfaceInternal(dialect);

    super(dialect, internalQueryInterface);
    this.#internalQueryInterface = internalQueryInterface;
  }

  async fetchDatabaseVersion(options?: FetchDatabaseVersionOptions): Promise<string> {
    const payload = await this.#internalQueryInterface.fetchDatabaseVersionRaw<{
      server_version: string;
    }>(options);

    return payload.server_version;
  }
}

export interface SnowflakeConnectionOptions
  extends Omit<
    SnowflakeSdk.ConnectionOptions,
    // "region" is not used by the Snowflake SDK anymore (deprecated option)
    | 'region'
    // ensures that the dialect produces values that Sequelize expects
    | 'fetchAsString'
    | 'jsTreatIntegerAsBigInt'
    | 'representNullAsStringNull'
    | 'rowMode'
    // conflicts with Sequelize's schema option. That option will be taken from Sequelize's options instead.
    | 'schema'
    // sequelize does not support result streaming https://github.com/sequelize/sequelize/issues/10347
    | 'streamResult'
    // "oauthHttpAllowed" is deprecated in the Snowflake SDK (for testing only; use oauthRedirectUri instead)
    | 'oauthHttpAllowed'
  > {}
